import{_ as a,o as t,c as o,ag as s}from"./chunks/framework.DXGyWiRo.js";const h=JSON.parse('{"title":"Plugin Knowledge Base (AI)","description":"","frontmatter":{},"headers":[],"relativePath":"guide/knowledge-base.md","filePath":"guide/knowledge-base.md","lastUpdated":1782660101000}'),i={name:"guide/knowledge-base.md"};function r(n,e,l,d,c,u){return t(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="plugin-knowledge-base-ai" tabindex="-1">Plugin Knowledge Base (AI) <a class="header-anchor" href="#plugin-knowledge-base-ai" aria-label="Permalink to &quot;Plugin Knowledge Base (AI)&quot;">​</a></h1><p>This page provides a knowledge base for AI assistants to better understand and work with the EasyYapi plugin. It is also the page the Rules tab&#39;s <strong>Help</strong> button opens.</p><h2 id="what-is-easyyapi" tabindex="-1">What is EasyYapi? <a class="header-anchor" href="#what-is-easyyapi" aria-label="Permalink to &quot;What is EasyYapi?&quot;">​</a></h2><p>EasyYapi is an IntelliJ IDEA plugin that generates API documentation from Java/Kotlin source code based on Javadoc, KDoc, and ScalaDoc comments.</p><h2 id="out-of-the-box" tabindex="-1">Out of the Box <a class="header-anchor" href="#out-of-the-box" aria-label="Permalink to &quot;Out of the Box&quot;">​</a></h2><p>EasyApi understands standard HTTP frameworks (Spring MVC, WebFlux, JAX-RS, Feign) out of the box — <strong>most projects need no custom rules</strong>. For custom framework behaviour the scanner can&#39;t see (e.g. a <code>jakarta.servlet.Filter</code> that requires a header, or a <code>ResponseBodyAdvice</code> that wraps every response in an envelope), use the built-in AI Assistant or the external skill to detect it and generate the rule. See <a href="/settings/rule-authoring">Rule Authoring</a> for the guide.</p><h2 id="key-concepts" tabindex="-1">Key Concepts <a class="header-anchor" href="#key-concepts" aria-label="Permalink to &quot;Key Concepts&quot;">​</a></h2><ul><li><strong>Folder-based rule files</strong> (3.0+): <code>.easyapi/*.rules</code> at project (<code>&lt;project&gt;/.easyapi/</code>) and global (<code>~/.easyapi/</code>) scopes — discovered automatically, reloaded on change. Legacy <code>.easy.api.config*</code> files are still read for backwards compatibility.</li><li><strong>Built-in AI Assistant</strong>: a provider-neutral AI service (LangChain4j-backed) embedded in the Rules tab (Chat / Magic buttons). Authors rules in natural language and never writes files without explicit approval.</li><li><strong>External <code>easy-yapi-assistant</code> skill</strong>: a skill you install (<code>npx skills add tangcent/easy-yapi -g -y</code>) so external AI coding assistants (Trae, Cursor, Cline, Continue, etc.) author rules from the same knowledge base as the built-in assistant.</li><li><strong>Configuration Rules</strong>: key-value pairs that customize documentation generation. See <a href="/settings/config-rule">Available Config Rules</a>.</li><li><strong>Groovy Scripts</strong>: advanced customization via the <code>groovy:</code> prefix. See <a href="/settings/tools">Script Tools</a>.</li><li><strong>Parse Events</strong>: callbacks that execute at specific points during the parsing process. See <a href="/settings/">Callbacks &amp; Events</a>.</li><li><strong>Script Tools</strong>: built-in utilities available in Groovy scripts.</li></ul><h2 id="ways-to-write-rules" tabindex="-1">Ways to Write Rules <a class="header-anchor" href="#ways-to-write-rules" aria-label="Permalink to &quot;Ways to Write Rules&quot;">​</a></h2><p>EasyYapi 3.x offers <strong>two ways</strong> to author rules. Both write to <code>.easyapi/*.rules</code> files. See <a href="/settings/rule-authoring">Rule Authoring</a> for the full guide.</p><table tabindex="0"><thead><tr><th>Way</th><th>Best for</th></tr></thead><tbody><tr><td><a href="/settings/rule-authoring#built-in-ai-assistant">Built-in AI Assistant</a></td><td>Natural-language rule creation in Settings → Rules → Chat / Magic</td></tr><tr><td><a href="/settings/rule-authoring#external-easy-yapi-assistant-skill">External <code>easy-yapi-assistant</code> skill</a></td><td>Driving rule authoring from an external AI coding assistant</td></tr></tbody></table><h2 id="common-workflows" tabindex="-1">Common Workflows <a class="header-anchor" href="#common-workflows" aria-label="Permalink to &quot;Common Workflows&quot;">​</a></h2><ol><li>Install the plugin from JetBrains Marketplace</li><li>Add Javadoc/KDoc comments to your code</li><li>(Optional) Author rules in <code>.easyapi/*.rules</code> files via the AI Assistant or the external skill</li><li>Export documentation to YApi, Postman, or Markdown</li></ol><h2 id="configuration-file-locations" tabindex="-1">Configuration File Locations <a class="header-anchor" href="#configuration-file-locations" aria-label="Permalink to &quot;Configuration File Locations&quot;">​</a></h2><ul><li><strong>Project rules (3.0+)</strong>: <code>&lt;project&gt;/.easyapi/*.rules</code></li><li><strong>Global rules (3.0+)</strong>: <code>~/.easyapi/*.rules</code></li><li><strong>Legacy project config</strong>: <code>.easy.api.config</code> (still read for backwards compatibility)</li><li><strong>Remote</strong>: configured via <code>remote.url</code></li></ul>',15)])])}const p=a(i,[["render",r]]);export{h as __pageData,p as default};
